import React from 'react';
import './BingoBoard.css';

function BingoBoard({ calledNumbers }) {
  // Generate numbers for each column - 15 rows per column
  const bingoColumns = {
    B: Array.from({ length: 15 }, (_, i) => i + 1),
    I: Array.from({ length: 15 }, (_, i) => i + 16),
    N: Array.from({ length: 15 }, (_, i) => i + 31),
    G: Array.from({ length: 15 }, (_, i) => i + 46),
    O: Array.from({ length: 15 }, (_, i) => i + 61)
  };

  // Check if a number has been called
  const isNumberCalled = (number) => {
    return calledNumbers.includes(number);
  };

  return (
    <div className="bingo-board glass-card">
      <h3>🎯 BINGO Number Board</h3>
      
      {/* Column Headers */}
      <div className="board-header">
        <div className="column-header">B</div>
        <div className="column-header">I</div>
        <div className="column-header">N</div>
        <div className="column-header">G</div>
        <div className="column-header">O</div>
      </div>
      
      {/* Board Body - 15 rows */}
      <div className="board-body">
        {[...Array(15)].map((_, rowIndex) => (
          <div key={rowIndex} className="board-row">
            {['B', 'I', 'N', 'G', 'O'].map(letter => {
              const number = bingoColumns[letter][rowIndex];
              const called = isNumberCalled(number);
              return (
                <div
                  key={`${letter}-${number}`}
                  className={`board-cell ${called ? 'called' : ''}`}
                  title={`${letter}${number} - ${called ? 'Called ✓' : 'Not Called'}`}
                >
                  {number}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      
      {/* Statistics */}
      <div className="board-stats">
        <span>📊 Called: {calledNumbers.length}/75</span>
        <span className="stats-badge">
          {calledNumbers.length === 0 && '🎯 Waiting...'}
          {calledNumbers.length > 0 && calledNumbers.length < 75 && `🎲 ${Math.round((calledNumbers.length / 75) * 100)}% Complete`}
          {calledNumbers.length === 75 && '🎉 BINGO COMPLETE!'}
        </span>
      </div>
    </div>
  );
}

export default BingoBoard;
